import os, base64, gzip
base = os.path.dirname(os.path.abspath(__file__))
FILES = [
  ('src\\\\app\\\\blog\\\\page.tsx', ''),
  ('src\\\\app\\\\blog\\\\[slug]\\\\page.tsx', ''),
  ('src\\\\app\\\\api\\\\blog\\\\route.ts', ''),
  ('src\\\\app\\\\api\\\\blog\\\\comentarios\\\\route.ts', ''),
  ('src\\\\app\\\\api\\\\blog\\\\curtidas\\\\route.ts', ''),
  ('src\\\\app\\\\api\\\\visitas\\\\route.ts', ''),
  ('src\\\\components\\\\ContadorVisitas.tsx', ''),
]
ok = 0
for rel, data in FILES:
    try:
        dest = os.path.join(base, rel)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, "w", encoding="utf-8", newline="\n") as f:
            f.write(gzip.decompress(base64.b64decode(data)).decode("utf-8"))
        print("OK:", rel)
        ok += 1
    except Exception as e:
        print("ERRO:", rel, e)

# Fix bolsas
import os, re
base = os.path.dirname(os.path.abspath(__file__))
fp = os.path.join(base, 'src', 'lib', 'menuConfig.ts')
with open(fp, 'r', encoding='utf-8') as f:
    c = f.read()
if 'Outras Marcas' not in c:
    c = c.replace(
        "{ label: 'Burberry', slug: 'burberry' },",
        "{ label: 'Burberry', slug: 'burberry' },\n      { label: 'Outras Marcas', slug: 'outras-marcas' },"
    )
    with open(fp, 'w', encoding='utf-8', newline='\n') as f:
        f.write(c)
    print('OK: Outras Marcas adicionado em Bolsas')
else:
    print('OK: Outras Marcas ja existe')

print()
print(f"Total: {ok}/7 arquivos instalados")
print("Blog + contador visitas + Outras Marcas em Bolsas!")
print("Rode: npm run build")